def test_transformer_encoder_variants(B, T, D, H, L, ff, seed):
    torch.manual_seed(seed)
    layer = nn.TransformerEncoderLayer(D, H, dim_feedforward=ff, batch_first=True)
    enc = nn.TransformerEncoder(layer, num_layers=L)
    x = torch.randn(B, T, D)
    out = enc(x)
    assert out.shape == (B, T, D)
