def test_conv1d_variants(B, C_in, C_out, L, k, seed):
    torch.manual_seed(seed)
    conv = nn.Conv1d(C_in, C_out, kernel_size=k, padding=k//2)
    x = torch.randn(B, C_in, L)
    out = conv(x)
    assert out.shape[0] == B
    assert out.shape[1] == C_out

