def test_gru_variants(B, T, D, H, L, bidirectional, seed):
    torch.manual_seed(seed)
    gru = nn.GRU(D, H, num_layers=L, batch_first=True, bidirectional=bidirectional)
    x = torch.randn(B, T, D)
    out, _ = gru(x)
    expected_H = H * (2 if bidirectional else 1)
    assert out.shape == (B, T, expected_H)
